// SharkByte backend envía payload normalizado
var body = $input.first().json.body || $input.first().json;
if (!body.tenantId || !body.senderId || !body.messageText) return [];
if (body.platform !== 'facebook') return [];
return [{ json: {
  platform: 'facebook',
  tenantId: body.tenantId,
  senderId: String(body.senderId),
  senderName: body.senderName || 'Cliente',
  messageText: body.messageText,
  messageId: body.messageId || '',
  timestamp: body.timestamp || Date.now(),
  pageId: body.pageId || ''
}}];

var msg = $('Normalizar Payload FB').first().json;
var tenant = $('Buscar Config Tenant').first().json;
var channel = $('Obtener Credenciales FB').first().json;

if (!channel || !channel.found) throw new Error('[FB] Canal no configurado para tenant ' + msg.tenantId);

var bc = tenant.businessConfig || {};
var refs = tenant.references || [];

// Horario
var tz = (bc.businessHours && bc.businessHours.timezone) ? bc.businessHours.timezone : 'America/Bogota';
var now = new Date();
var localTime = new Intl.DateTimeFormat('es-CO',{timeZone:tz,hour:'2-digit',minute:'2-digit',hourCycle:'h23'}).format(now);
var dayName = new Intl.DateTimeFormat('es-CO',{timeZone:tz,weekday:'long'}).format(now);
var schedule = (bc.businessHours && bc.businessHours.schedule) ? bc.businessHours.schedule : [];
var todaySchedule = schedule.find(function(d){ return (d.day||'').toLowerCase()===dayName.toLowerCase(); });
var parts = localTime.split(':'); var nowMins = parseInt(parts[0],10)*60+parseInt(parts[1],10);
var inHours = true;
if (todaySchedule && todaySchedule.isOpen) {
  var op=(todaySchedule.open||'00:00').split(':'); var cl=(todaySchedule.close||'23:59').split(':');
  inHours = nowMins>=(parseInt(op[0],10)*60+parseInt(op[1],10)) && nowMins<=(parseInt(cl[0],10)*60+parseInt(cl[1],10));
} else if (todaySchedule && !todaySchedule.isOpen) { inHours=false; }

// Catalogo
var catalogLines=(bc.catalog||[]).map(function(p){
  var l='- '+p.name; if(p.price) l+=' | $'+Number(p.price).toLocaleString('es-CO');
  if(p.category) l+=' | '+p.category; if(p.available===false) l+=' [NO DISPONIBLE]';
  if(p.description) l+=': '+p.description; return l;
});

// FAQ
var faqLines=(bc.faq||[]).map(function(f){ return 'P: '+f.question+'\nR: '+f.answer; });

// Referencias
var refsText='';
if(refs.length>0){
  refsText='\n\nFUENTES DE REFERENCIA (datos reales del negocio):\n';
  refs.forEach(function(r){ refsText+='- ['+r.type.toUpperCase()+'] '+r.name+': '+r.url; if(r.description) refsText+=' — '+r.description; refsText+='\n'; });
}

// System prompt
var classInstr='INSTRUCCION CRITICA: Al FINAL de tu respuesta SIEMPRE agrega:\n<JSON>\n{"intent":"INTENT","confidence":SCORE}\n</JSON>\nINTENT: ventas|soporte|agendamiento|informacion|humano|fallback\n\n';
var rawSys=classInstr+'=== INSTRUCCIONES DEL NEGOCIO ===\n'+(bc.aiInstructions||'Eres un asistente de atencion al cliente profesional y amable.')+'\n\nNegocio: '+(bc.businessName||'')+'\nCanal: Facebook Messenger\nTono: '+(bc.tone||'amigable')+'\n\nCATALOGO:\n'+(catalogLines.length>0?catalogLines.join('\n'):'Sin productos.')+'\n\nFAQ:\n'+(faqLines.length>0?faqLines.join('\n\n'):'Sin FAQ.')+((bc.paymentMethods&&bc.paymentMethods.length>0)?'\nMetodos de pago: '+bc.paymentMethods.join(', '):'')+refsText+'\n\nCliente: '+(msg.senderName||'Cliente');
var oe='{{'; var ce='}}';
var systemMessage=rawSys.split('{').join(oe).split('}').join(ce);

return [{ json: {
  platform:'facebook', tenantId:msg.tenantId, senderId:msg.senderId,
  senderName:msg.senderName, message:msg.messageText, pageId:msg.pageId,
  accessToken:channel.accessToken||'',
  inHours:inHours, outOfHoursMessage:bc.outOfHoursMessage||'Estamos fuera de horario. Te responderemos pronto.',
  systemMessage:systemMessage
}}];

var ctx = $('Construir Contexto IA').first().json;
var output = $('Agente IA Facebook').first().json.output || '';
var clean = output.replace(/<JSON>[\s\S]*?<\/JSON>/g,'').trim();
return [{ json: { platform:'facebook', tenantId:ctx.tenantId, senderId:ctx.senderId, senderName:ctx.senderName, messageText:ctx.message, responseText:clean, accessToken:ctx.accessToken } }];
